#!/usr/bin/env node
import { writeFileSync } from 'node:fs';
import { resolve } from 'node:path';
import { inspectStoneCairo1Fact } from '../src/integrity/stone-fact.mjs';

function usage() {
  return `Usage:
  node tools/inspect-stone-fact.mjs --stone-proof <path> [options]

Options:
  --stone-proof <path>   Stone proof JSON generated by cpu_air_prover.
  --out <path>           Output JSON path.
  --text                 Print compact status.

This extracts the Cairo1 program/output split used by Integrity's cairo1 memory
verification path and computes:
  program_hash, output_hash, fact_hash
`;
}

function parseArgs(argv) {
  const args = {
    stoneProofPath: undefined,
    out: undefined,
    text: false,
  };
  for (let i = 0; i < argv.length; i += 1) {
    const arg = argv[i];
    if (arg === '--help' || arg === '-h') {
      console.log(usage());
      process.exit(0);
    } else if (arg === '--stone-proof') {
      args.stoneProofPath = argv[++i];
    } else if (arg === '--out') {
      args.out = argv[++i];
    } else if (arg === '--text') {
      args.text = true;
    } else {
      throw new Error(`unknown argument: ${arg}`);
    }
  }
  if (!args.stoneProofPath) {
    throw new Error(`missing --stone-proof\n\n${usage()}`);
  }
  return args;
}

const args = parseArgs(process.argv.slice(2));
const result = inspectStoneCairo1Fact(resolve(args.stoneProofPath));
if (args.out) {
  writeFileSync(resolve(args.out), `${JSON.stringify(result, null, 2)}\n`);
}

if (args.text) {
  process.stdout.write(
    [
      `Program hash: ${result.programHash}`,
      `Output hash: ${result.outputHash}`,
      `Fact hash: ${result.factHash}`,
      `Program cells: ${result.publicInput.programCells}`,
      `Output cells: ${result.publicInput.outputCells}`,
      args.out ? `Stone fact JSON: ${resolve(args.out)}` : undefined,
    ]
      .filter(Boolean)
      .join('\n') + '\n',
  );
} else {
  process.stdout.write(`${JSON.stringify(result, null, 2)}\n`);
}
